nodes.inputScript:
// Alias the implementation plan into a stable global key for downstream agents. If we're
// invoked as a subflow after impl-plan-flow, the plan is already in workflow.currentPlan; if
// we're invoked standalone, the plan arrives as the input artifact.
var plan = (global && workflow.currentPlan) ? workflow.currentPlan : (input && input.text) ? input.text : '';
if (plan) { setWorkflow('implPlan', plan); }

nodes.outputScript:
var ts = workflow.taskStatus;
var tasks = (ts && ts.tasks) ? ts.tasks : [];
var hasBlockedOrDeferred = false;
for (var i = 0; i < tasks.length; i++) {
  if (tasks[i].status === 'blocked' || tasks[i].status === 'deferred') {
    hasBlockedOrDeferred = true;
    break;
  }
}
setNodePath(hasBlockedOrDeferred ? 'HasBlocked' : 'AllGood');

if (output.decision === 'Approved') {
  setOutput(workflow.currentPlan);
} else if (output.decision === 'Rejected') {
  setWorkflow('latestRejection', output.text);
  var prior = workflow.rejectionHistory || '';
  var entry = '## Round ' + round + '\n' + output.text;
  setWorkflow('rejectionHistory', prior ? prior + '\n\n' + entry : entry);
}

nodes.inputScript:
// Seed the repositories array into the workflow bag so it survives across the prd-intake / impl-plan /
// dev-flow subflow boundaries. (Subflow children inherit workflow vars but NOT local context.)
if (context && context.repositories) {
  setWorkflow('repositories', context.repositories);
}

nodes.outputScript:
if (output.decision === 'Rejected') {
  var prior = workflow.prdRejectionHistory || '';
  var entry = '## Round ' + round + '\n' + output.text;
  setWorkflow('prdRejectionHistory', prior ? prior + '\n\n' + entry : entry);
}

